from django.shortcuts import render, redirect, get_object_or_404
from django.views import View
from django.views.generic import TemplateView, ListView, DetailView
from django.contrib.auth.mixins import UserPassesTestMixin
from django.contrib.auth.models import User
from django.contrib import messages
from django.db.models import Q
from catalog.models import Barco, Categoria, Puerto, Fabricante
from reservations.models import Reserva, LineaReserva, HistorialReserva
from .forms import BarcoForm

class AdminRequiredMixin(UserPassesTestMixin):
    def test_func(self):
        return self.request.user.is_staff and self.request.user.is_superuser

    def handle_no_permission(self):
        messages.error(self.request, 'No tienes permiso para acceder a esta página.')
        return redirect('/')

class AdminDashboardView(AdminRequiredMixin, TemplateView):
    template_name = 'admin_panel/dashboard.html'

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        context['total_barcos'] = Barco.objects.count()
        context['total_clientes'] = User.objects.filter(is_staff=False).count()
        context['total_reservas'] = Reserva.objects.count()
        context['reservas_pendientes'] = Reserva.objects.filter(estado='PENDIENTE_DE_PAGO').count()
        return context

class AdminBoatsListView(AdminRequiredMixin, ListView):
    model = Barco
    template_name = 'admin_panel/boats.html'
    context_object_name = 'barcos'
    paginate_by = 20

    def get_queryset(self):
        queryset = Barco.objects.all()
        search = self.request.GET.get('search')
        if search:
            queryset = queryset.filter(
                Q(nombre__icontains=search) | Q(descripcion__icontains=search)
            )
        return queryset.order_by('-created_at')

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        context['search'] = self.request.GET.get('search', '')
        return context

class AdminBoatCreateView(AdminRequiredMixin, View):
    def get(self, request):
        form = BarcoForm()
        return render(request, 'admin_panel/boat_form.html', {'form': form, 'action': 'crear'})

    def post(self, request):
        form = BarcoForm(request.POST, request.FILES)
        if form.is_valid():
            barco = form.save()
            messages.success(request, f'Barco "{barco.nombre}" creado exitosamente.')
            return redirect('admin_panel:boats_list')
        return render(request, 'admin_panel/boat_form.html', {'form': form, 'action': 'crear'})

class AdminBoatEditView(AdminRequiredMixin, View):
    def get(self, request, id):
        barco = get_object_or_404(Barco, id=id)
        form = BarcoForm(instance=barco)
        return render(request, 'admin_panel/boat_form.html', {'form': form, 'barco': barco, 'action': 'editar'})

    def post(self, request, id):
        barco = get_object_or_404(Barco, id=id)
        form = BarcoForm(request.POST, request.FILES, instance=barco)
        if form.is_valid():
            barco = form.save()
            messages.success(request, f'Barco "{barco.nombre}" actualizado exitosamente.')
            return redirect('admin_panel:boats_list')
        return render(request, 'admin_panel/boat_form.html', {'form': form, 'barco': barco, 'action': 'editar'})

class AdminBoatDeleteView(AdminRequiredMixin, View):
    def post(self, request, id):
        barco = get_object_or_404(Barco, id=id)
        nombre = barco.nombre

        reservas_activas = LineaReserva.objects.filter(
            barco=barco,
            reserva__estado__in=['PENDIENTE_DE_PAGO', 'PAGADO', 'EN_USO']
        ).exists()

        if reservas_activas:
            messages.error(request, f'No se puede eliminar el barco "{nombre}" porque tiene reservas activas.')
            return redirect('admin_panel:boats_list')

        barco.delete()
        messages.success(request, f'Barco "{nombre}" eliminado exitosamente.')
        return redirect('admin_panel:boats_list')

class AdminClientsListView(AdminRequiredMixin, ListView):
    model = User
    template_name = 'admin_panel/clients.html'
    context_object_name = 'clientes'
    paginate_by = 20

    def get_queryset(self):
        queryset = User.objects.filter(is_staff=False)
        search = self.request.GET.get('search')
        if search:
            queryset = queryset.filter(
                Q(email__icontains=search) | Q(first_name__icontains=search) | Q(last_name__icontains=search)
            )
        return queryset.order_by('-date_joined')

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        context['search'] = self.request.GET.get('search', '')
        return context

class AdminClientDeleteView(AdminRequiredMixin, View):
    def post(self, request, id):
        cliente = get_object_or_404(User, id=id, is_staff=False)

        reservas_pendientes = Reserva.objects.filter(
            cliente=cliente,
            estado__in=['PENDIENTE_DE_PAGO', 'PAGADO', 'EN_USO']
        ).exists()

        if reservas_pendientes:
            messages.error(request, f'No se puede eliminar el cliente porque tiene reservas pendientes.')
            return redirect('admin_panel:clients_list')

        email = cliente.email
        cliente.delete()
        messages.success(request, f'Cliente "{email}" eliminado exitosamente.')
        return redirect('admin_panel:clients_list')

class AdminReservationsListView(AdminRequiredMixin, ListView):
    model = Reserva
    template_name = 'admin_panel/reservations.html'
    context_object_name = 'reservas'
    paginate_by = 20

    def get_queryset(self):
        queryset = Reserva.objects.all()
        estado = self.request.GET.get('estado')
        if estado:
            queryset = queryset.filter(estado=estado)
        return queryset.order_by('-created_at')

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        context['estados'] = Reserva.ESTADO_CHOICES
        context['estado_selected'] = self.request.GET.get('estado', '')
        return context

class AdminReservationDetailView(AdminRequiredMixin, DetailView):
    model = Reserva
    template_name = 'admin_panel/reservation_detail.html'
    context_object_name = 'reserva'
    slug_field = 'codigo_seguimiento'
    slug_url_kwarg = 'codigo'

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        reserva = self.get_object()
        context['lineas'] = LineaReserva.objects.filter(reserva=reserva)
        context['historial'] = HistorialReserva.objects.filter(reserva=reserva).order_by('-timestamp')
        context['transiciones_validas'] = self._get_transiciones_validas(reserva.estado)
        return context

    def _get_transiciones_validas(self, estado_actual):
        transiciones = {
            'PENDIENTE_DE_PAGO': ['PAGADO'],
            'PAGADO': ['EN_USO'],
            'EN_USO': ['DEVUELTO'],
            'DEVUELTO': [],
        }
        return transiciones.get(estado_actual, [])

class AdminChangeReservationStateView(AdminRequiredMixin, View):
    def post(self, request, codigo):
        reserva = get_object_or_404(Reserva, codigo_seguimiento=codigo)
        nuevo_estado = request.POST.get('nuevo_estado')

        transiciones_validas = {
            'PENDIENTE_DE_PAGO': ['PAGADO'],
            'PAGADO': ['EN_USO'],
            'EN_USO': ['DEVUELTO'],
            'DEVUELTO': [],
        }

        if nuevo_estado not in transiciones_validas.get(reserva.estado, []):
            messages.error(request, 'Transición de estado no válida.')
            return redirect('admin_panel:reservation_detail', codigo=codigo)

        estado_anterior = reserva.estado
        reserva.estado = nuevo_estado
        reserva.save()

        HistorialReserva.objects.create(
            reserva=reserva,
            estado_anterior=estado_anterior,
            estado_nuevo=nuevo_estado,
            cambio_realizado_por=request.user,
            notas=request.POST.get('notas', '')
        )

        messages.success(request, f'Estado de la reserva actualizado a {nuevo_estado}.')
        return redirect('admin_panel:reservation_detail', codigo=codigo)

