            messages.error(request, 'Por favor, completa el paso 1 primero.')
            return redirect('reservations:step1')

        form = ReservationStep2Form()

        if request.user.is_authenticated:
            form.fields['nombre_cliente'].initial = request.user.first_name or ''
            form.fields['apellido_cliente'].initial = request.user.last_name or ''
            form.fields['email_contacto'].initial = request.user.email
