            return redirect('reservations:step3')

        return render(request, 'reservations/step2.html', {'form': form})

class ReservationStep3View(View):
    def get(self, request):
        if 'reservation_fecha_inicio' not in request.session or 'reservation_nombre' not in request.session:
            messages.error(request, 'Por favor, completa los pasos anteriores primero.')
            return redirect('reservations:step1')

        cart = CartService.get_cart(request)
        if not cart:
            messages.error(request, 'Tu cesta está vacía.')
            return redirect('cart:view')

        fecha_inicio = request.session.get('reservation_fecha_inicio')
        fecha_fin = request.session.get('reservation_fecha_fin')

        from datetime import datetime
        fecha_inicio_obj = datetime.strptime(fecha_inicio, '%Y-%m-%d').date()
        fecha_fin_obj = datetime.strptime(fecha_fin, '%Y-%m-%d').date()
        dias = (fecha_fin_obj - fecha_inicio_obj).days

        cart_items = []
        importe_alquiler = Decimal('0')
        importe_combustible = Decimal('0')

        for barco_id_str, item in cart.items():
            try:
                barco = Barco.objects.get(id=int(barco_id_str))
                cantidad = item['cantidad']
                precio_dia = Decimal(item['precio_dia'])

                tasa_combustible = Decimal('50')
                if barco.categoria.nombre.lower() == 'velero':
                    tasa_combustible = Decimal('0')

                subtotal_alquiler = precio_dia * dias * cantidad
                subtotal_combustible = tasa_combustible * dias * cantidad

                importe_alquiler += subtotal_alquiler
                importe_combustible += subtotal_combustible

                item['barco'] = barco
                item['dias'] = dias
                item['tasa_combustible'] = tasa_combustible
                item['subtotal_alquiler'] = subtotal_alquiler
                item['subtotal_combustible'] = subtotal_combustible
                cart_items.append(item)
            except Barco.DoesNotExist:
                pass

        importe_total = importe_alquiler + importe_combustible

        form = ReservationStep3Form()
        context = {
            'form': form,
            'cart_items': cart_items,
            'dias': dias,
            'importe_alquiler': importe_alquiler,
            'importe_combustible': importe_combustible,
            'importe_total': importe_total,
            'fecha_inicio': fecha_inicio,
            'fecha_fin': fecha_fin,
        }

        return render(request, 'reservations/step3.html', context)

    def post(self, request):
        if 'reservation_fecha_inicio' not in request.session or 'reservation_nombre' not in request.session:
            messages.error(request, 'Por favor, completa los pasos anteriores primero.')
            return redirect('reservations:step1')

        cart = CartService.get_cart(request)
        if not cart:
            messages.error(request, 'Tu cesta está vacía.')
            return redirect('cart:view')

        form = ReservationStep3Form(request.POST)
        if form.is_valid():
            metodo_pago = form.cleaned_data['metodo_pago']

            fecha_inicio = request.session.get('reservation_fecha_inicio')
            fecha_fin = request.session.get('reservation_fecha_fin')
            nombre = request.session.get('reservation_nombre')
            apellido = request.session.get('reservation_apellido')
            email = request.session.get('reservation_email')
            telefono = request.session.get('reservation_telefono', '')

            from datetime import datetime
            fecha_inicio_obj = datetime.strptime(fecha_inicio, '%Y-%m-%d').date()
            fecha_fin_obj = datetime.strptime(fecha_fin, '%Y-%m-%d').date()
            dias = (fecha_fin_obj - fecha_inicio_obj).days

            importe_alquiler = Decimal('0')
            importe_combustible = Decimal('0')

            reserva = Reserva.objects.create(
                cliente=request.user if request.user.is_authenticated else None,
                email_contacto=email,
                nombre_cliente=nombre,
                apellido_cliente=apellido,
                telefono_cliente=telefono,
                fecha_inicio=fecha_inicio_obj,
                fecha_fin=fecha_fin_obj,
                metodo_pago=metodo_pago,
                estado='PENDIENTE_DE_PAGO'
            )

            for barco_id_str, item in cart.items():
                try:
                    barco = Barco.objects.get(id=int(barco_id_str))
                    cantidad = item['cantidad']
                    precio_dia = Decimal(item['precio_dia'])

                    tasa_combustible = Decimal('50')
                    if barco.categoria.nombre.lower() == 'velero':
                        tasa_combustible = Decimal('0')

                    subtotal_alquiler = precio_dia * dias * cantidad
                    subtotal_combustible = tasa_combustible * dias * cantidad

                    importe_alquiler += subtotal_alquiler
                    importe_combustible += subtotal_combustible

                    LineaReserva.objects.create(
                        reserva=reserva,
                        barco=barco,
                        cantidad=cantidad,
                        precio_unitario_dia=precio_dia,
                        tasa_combustible_dia=tasa_combustible
                    )
                except Barco.DoesNotExist:
                    pass

            importe_total = importe_alquiler + importe_combustible
            reserva.importe_total = importe_total
            reserva.importe_combustible = importe_combustible
            reserva.save()

            HistorialReserva.objects.create(
                reserva=reserva,
                estado_anterior='',
                estado_nuevo='PENDIENTE_DE_PAGO',
                cambio_realizado_por=request.user if request.user.is_authenticated else None,
                notas='Reserva creada'
            )

            if metodo_pago == 'paypal':
                request.session['reservation_id'] = reserva.id
                request.session.modified = True
                return redirect('reservations:paypal_callback')
            else:
                self._enviar_confirmacion(reserva)
                CartService.clear_cart(request)
                self._limpiar_sesion(request)
                return redirect('reservations:confirmation')

        return render(request, 'reservations/step3.html', {'form': form})

    def _enviar_confirmacion(self, reserva):
        lineas = LineaReserva.objects.filter(reserva=reserva)
        detalles_barcos = '\n'.join([f'- {linea.barco.nombre} x {linea.cantidad}' for linea in lineas])

        asunto = f'Confirmación de reserva - {reserva.codigo_seguimiento}'
        mensaje = f'''Hola {reserva.nombre_cliente},

Tu reserva ha sido confirmada.

Código de seguimiento: {reserva.codigo_seguimiento}
Fecha de inicio: {reserva.fecha_inicio}
Fecha de fin: {reserva.fecha_fin}

Barcos:
{detalles_barcos}

Importe total: {reserva.importe_total}€
Método de pago: Contra Reembolso

Puedes consultar el estado de tu reserva en: /seguimiento/{reserva.codigo_seguimiento}/

Gracias por usar Hundidos.
'''

        send_mail(
            asunto,
            mensaje,
            settings.DEFAULT_FROM_EMAIL,
            [reserva.email_contacto],
            fail_silently=True
        )

    def _limpiar_sesion(self, request):
        keys_to_delete = [
            'reservation_fecha_inicio',
            'reservation_fecha_fin',
            'reservation_nombre',
            'reservation_apellido',
            'reservation_email',
            'reservation_telefono',
            'reservation_id'
        ]
        for key in keys_to_delete:
            if key in request.session:
                del request.session[key]
        request.session.modified = True

