class CancelReservationView(View):
    def post(self, request, codigo):
        try:
            reserva = Reserva.objects.get(codigo_seguimiento=codigo)
        except Reserva.DoesNotExist:
            messages.error(request, 'No se encontró la reserva.')
            return redirect('tracking:search')

        if reserva.estado != 'PENDIENTE_DE_PAGO':
            messages.error(request, 'Solo se pueden cancelar reservas en estado PENDIENTE DE PAGO.')
            return redirect('tracking:detail', codigo=codigo)

        reserva.delete()
        messages.success(request, 'Reserva cancelada correctamente.')
        return redirect('tracking:search')
